document.addEventListener("DOMContentLoaded", () => {
setupMobileMenu();
setupTheme();
setupLanguage();
setupInteractivePanel();
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
const theme = document.body.classList.contains("light-mode") ? "light" : "dark";
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
if (langSelect) {
langSelect.value = currentLang;
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
});
}
updatePageLanguage(currentLang);
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
element.textContent = translations[key][lang];
}
});
const nameInput = document.getElementById("formName");
if (nameInput) {
nameInput.placeholder = lang === "tr" ? "Örn: Ahmet Yılmaz" : "e.g. John Doe";
}
const emailInput = document.getElementById("formEmail");
if (emailInput) {
emailInput.placeholder = lang === "tr" ? "ahmet@example.com" : "john@example.com";
}
const phoneInput = document.getElementById("formPhone");
if (phoneInput) {
phoneInput.placeholder = lang === "tr" ? "+90 (555) 123 4567" : "+1 (555) 123 4567";
}
const messageInput = document.getElementById("formMessage");
if (messageInput) {
messageInput.placeholder = lang === "tr"
? "Sorularınızı veya taleplerinizi buraya yazabilirsiniz..."
: "Write your questions or requests here...";
}
const otherCapacityInput = document.getElementById("formOtherCapacity");
if (otherCapacityInput) {
otherCapacityInput.placeholder = lang === "tr"
? "Hangi sıfatla ulaştığınızı detaylandırın..."
: "Please elaborate in what capacity you are reaching out...";
}
}
function setupInteractivePanel() {
const selectionPanel = document.getElementById("contactSelectionPanel");
const formPanel = document.getElementById("contactFormPanel");
const showFormBtn = document.getElementById("showFormBtn");
const backToSelectionBtn = document.getElementById("backToSelectionBtn");
const contactForm = document.getElementById("siteContactForm");
const successMessage = document.getElementById("formSuccessMessage");
const successBackBtn = document.getElementById("successBackBtn");
if (!selectionPanel || !formPanel) return;
if (showFormBtn) {
showFormBtn.addEventListener("click", () => {
selectionPanel.style.display = "none";
formPanel.style.display = "block";
contactForm.style.display = "block";
successMessage.style.display = "none";
formPanel.scrollIntoView({ behavior: "smooth" });
});
}
if (backToSelectionBtn) {
backToSelectionBtn.addEventListener("click", () => {
formPanel.style.display = "none";
selectionPanel.style.display = "block";
selectionPanel.scrollIntoView({ behavior: "smooth" });
});
}
if (contactForm) {
contactForm.addEventListener("submit", (e) => {
e.preventDefault();
const lang = localStorage.getItem("language") || "tr";
const name = document.getElementById("formName").value;
const email = document.getElementById("formEmail").value;
const phone = document.getElementById("formPhone").value;
const capacityVal = document.getElementById("formCapacity").value;
const otherCapacity = document.getElementById("formOtherCapacity") ? document.getElementById("formOtherCapacity").value : "";
const returnVal = document.getElementById("formReturnMethod").value;
const message = document.getElementById("formMessage").value;
let capacityLabel = "";
if (capacityVal === "student") capacityLabel = lang === "tr" ? "Öğrenci Adayı" : "Prospective Student";
else if (capacityVal === "corporate") capacityLabel = lang === "tr" ? "Kurumsal / Şirket Temsilcisi" : "Corporate / Company Representative";
else if (capacityVal === "partner") capacityLabel = lang === "tr" ? "Eğitmen / İş Ortağı" : "Instructor / Partner";
else if (capacityVal === "other") capacityLabel = (lang === "tr" ? "Diğer: " : "Other: ") + otherCapacity;
let returnLabel = "";
if (returnVal === "email") returnLabel = lang === "tr" ? "E-Posta Göndererek" : "By Sending an Email";
else if (returnVal === "call") returnLabel = lang === "tr" ? "Telefonla Arayarak" : "By Phone Call";
else if (returnVal === "whatsapp") returnLabel = lang === "tr" ? "WhatsApp Mesajı Yazarak" : "By Writing on WhatsApp";
const timestamp = new Date().toLocaleString(lang === "tr" ? "tr-TR" : "en-US");
const fileTitle = lang === "tr" ? "SAPMAZ ACADEMY - YENİ İLETİŞİM FORMU TALEBİ" : "SAPMAZ ACADEMY - NEW CONTACT FORM REQUEST";
const fileDateLabel = lang === "tr" ? "Gönderim Tarihi" : "Submission Date";
const fileNameLabel = lang === "tr" ? "Ad Soyad" : "Full Name";
const fileEmailLabel = lang === "tr" ? "E-Posta Adresi" : "Email Address";
const filePhoneLabel = lang === "tr" ? "Telefon No" : "Phone Number";
const fileCapacityLabel = lang === "tr" ? "Başvuru Sıfatı" : "Applicant Capacity";
const fileReturnLabel = lang === "tr" ? "Dönüş Yöntemi" : "Response Preference";
const fileMsgLabel = lang === "tr" ? "Mesaj Detayı" : "Message Detail";
const submissionText = `==================================================
${fileTitle}
==================================================
${fileDateLabel.padEnd(20)} : ${timestamp}
--------------------------------------------------
${fileNameLabel.padEnd(20)} : ${name}
${fileEmailLabel.padEnd(20)} : ${email}
${filePhoneLabel.padEnd(20)} : ${phone}
${fileCapacityLabel.padEnd(20)} : ${capacityLabel}
${fileReturnLabel.padEnd(20)} : ${returnLabel}
--------------------------------------------------
${fileMsgLabel}:
--------------------------------------------------
${message || "-"}
==================================================
`;
try {
const blob = new Blob([submissionText], { type: "text/plain;charset=utf-8" });
const link = document.createElement("a");
link.href = URL.createObjectURL(blob);
const cleanName = name.trim().toLowerCase().replace(/[^a-z0-9]/g, "_");
link.download = `sapmaz_contact_${cleanName || "request"}.txt`;
document.body.appendChild(link);
link.click();
document.body.removeChild(link);
URL.revokeObjectURL(link.href);
} catch (err) {
console.error("Failed to download submission file:", err);
}
contactForm.style.display = "none";
successMessage.style.display = "block";
formPanel.scrollIntoView({ behavior: "smooth" });
});
}
if (successBackBtn) {
successBackBtn.addEventListener("click", () => {
window.location.href = "../index.html";
});
}
const formCapacity = document.getElementById("formCapacity");
const otherCapacityWrapper = document.getElementById("otherCapacityWrapper");
const formOtherCapacity = document.getElementById("formOtherCapacity");
if (formCapacity && otherCapacityWrapper && formOtherCapacity) {
formCapacity.addEventListener("change", (e) => {
if (e.target.value === "other") {
otherCapacityWrapper.style.display = "block";
formOtherCapacity.required = true;
} else {
otherCapacityWrapper.style.display = "none";
formOtherCapacity.required = false;
formOtherCapacity.value = "";
}
});
}
}